## Key Code

### 1. System Prompt Injection (runner.js)
```js
// Extension runner chains before_agent_start handlers across all extensions
async emitBeforeAgentStart(prompt, images, systemPrompt, systemPromptOptions) {
    let currentSystemPrompt = systemPrompt;
    for (const ext of this.extensions) {
        const handlers = ext.handlers.get("before_agent_start");
        for (const handler of handlers) {
            const handlerResult = await handler(event, ctx);
            if (result.systemPrompt !== undefined) {
                currentSystemPrompt = result.systemPrompt;  // Chain: each extension modifies prompt
                systemPromptModified = true;
            }
        }
    }
    return { systemPrompt: systemPromptModified ? currentSystemPrompt : undefined };
}
```

### 2. Orchestrator Delegation Instructions (index.ts)
```ts
pi.on("before_agent_start", async (event, ctx) => {
    clearPlanPanel(ctx);
    pi.setActiveTools(["delegate"]);  // Strip ALL tools except delegate
    const cleanedPrompt = event.systemPrompt.replace(TOOLS_SECTION_REGEX, "");  // Remove contradictory tool listings
    return { systemPrompt: cleanedPrompt + delegationInstructions };
});

pi.on("tool_call", async (event, ctx) => {
    if (event.toolName !== "delegate") {
        return { block: true, reason: `Orchestrator mode: use delegate() instead of ${event.toolName}` };
    }
});
```

### 3. Subagent Session Creation (subagent-runner.ts)
```ts
export async function runSubagent(specialist, task, cwd, parentCtx, signal, onUpdate, ...) {
    _batchLoadSubagent++;
    process.env[SUBAGENT_ENV_KEY] = "1";  // Prevent orchestrator re-registration
    try {
        loader = new DefaultResourceLoader({
            cwd, agentDir: getAgentDir(),
            systemPromptOverride: () => specialist.systemPrompt,  // <-- SPECIALIST PROMPT OVERRIDE
            noContextFiles: true,
        });
        const { session } = await createAgentSession({
            cwd, model, tools: specialist.tools,  // <-- TOOL RESTRICTION
            resourceLoader: loader,
            sessionManager: SessionManager.inMemory(cwd),  // <-- IN-MEMORY (no disk persistence)
            authStorage, modelRegistry,
        });
        await session.prompt(task);
    } finally {
        _batchLoadSubagent--;
        delete process.env[SUBAGENT_ENV_KEY];
    }
}
```

