### 7. Persistence Mechanism (agent-session.js)
```js
// Session persistence: messages saved on message_end
_handleAgentEvent = async (event) => {
    if (event.type === "message_end") {
        if (event.message.role === "custom") {
            this.sessionManager.appendCustomMessageEntry(...);
        } else {
            this.sessionManager.appendMessage(event.message);
        }
    }
};

// Extension state persistence
appendEntry: (customType, data) => {
    this.sessionManager.appendCustomEntry(customType, data);
};

// Message delivery queues
_steeringMessages = [];  // High priority, processed immediately during streaming
